arguments.sparql_query:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX crit: <http://purl.org/futuram/criticality#>
PREFIX mw: <https://purl.org/metalwheel#>
SELECT DISTINCT ?elemCls ?elemLabel ?imp ?baseMetal ?proc WHERE {
  VALUES ?elemName { ("Silver" "Gold" "Copper" "Palladium" "Iron" "Aluminium") }
  ?elemCls rdfs:label ?elemLabel . FILTER(STR(?elemLabel) = STR(?elemName))
  OPTIONAL { ?elemCls rdfs:subClassOf ?chebi . FILTER(CONTAINS(STR(?chebi), "CHEBI"))
             ?chebi crit:remark ?flag .
             OPTIONAL { ?flag crit:importance ?imp } }
  OPTIONAL { ?elemCls rdfs:subClassOf ?chebi2 . FILTER(CONTAINS(STR(?chebi2), "CHEBI"))
             ?chebi2 mw:hasRecoveryInformation ?ri .
             ?ri mw:hasBaseMetal ?bmChebi ;
                 mw:hasExpectedRecoveryEffectiveness ?eff ;
                 mw:hasRecoveryProcess ?proc .
             FILTER(?eff IN (mw:TargetedElement, mw:MainlyRecoveredElement))
             ?baseMetal rdfs:subClassOf ?bmChebi . FILTER(CONTAINS(STR(?bmChebi), "CHEBI"))
             FILTER NOT EXISTS { ?baseMetal rdfs:subClassOf ?mid . ?mid rdfs:subClassOf ?bmChebi . FILTER(?mid != ?baseMetal) } }
}

