PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?cls ?label ?slice ?year WHERE {
  ?cls rdfs:subClassOf futuram:V0301030000 .
  ?cls futuram:referenceYear ?year .
  OPTIONAL { ?cls rdfs:label ?label }
  OPTIONAL { ?cls futuram:sliceAxis ?slice }
  FILTER(?year >= 2024 && ?year <= 2030)
} ORDER BY ?year

