  OPTIONAL { ?cls rdfs:label ?label }
  FILTER(CONTAINS(LCASE(STR(?label)), "2025") || CONTAINS(STR(?cls), "2025") || CONTAINS(LCASE(STR(?cls)), "v2025"))
} LIMIT 20

